import type * as DMMF from '@prisma/dmmf'

/**
 * Renders all Prisma enums as TypeScript string union types.
 * Returns an empty string when the schema has no enums.
 */
export function renderEnums(enums: readonly DMMF.DatamodelEnum[]): string {
  if (enums.length === 0) return ''

  const lines: string[] = ['// ----- Enums -----', '']

  for (const e of enums) {
    const values = e.values.map((v) => `'${v.name}'`).join(' | ')
    lines.push(`export type ${e.name} = ${values}`)
    lines.push('')
  }

  return lines.join('\n')
}

