import type { FieldDefault } from '@prisma/dmmf'
import type * as DMMF from '@prisma/dmmf'
import { scalarToTs } from './scalar-to-ts'

/** Relation fields carry no REST-transferable data and are omitted from interfaces. */
function isDataField(field: DMMF.Field): boolean {
  return field.kind === 'scalar' || field.kind === 'enum'
}

/** Returns the TypeScript type string for a scalar or enum field. */
function fieldTsType(field: DMMF.Field): string {
  const base = field.kind === 'enum' ? field.type : scalarToTs(field.type)
  const listed = field.isList ? `${base}[]` : base
  return field.isRequired ? listed : `${listed} | null`
}

/**
 * A field is auto-generated when its default value is a server-side function
 * (autoincrement, cuid, uuid, now, auto). Such fields are excluded from
 * CreateInput because the database supplies them automatically.
 */
function isAutoGenerated(field: DMMF.Field): boolean {
  if (!field.hasDefaultValue || field.default === undefined) return false
  const d = field.default
  if (typeof d === 'object' && !Array.isArray(d)) {
    const name = (d as FieldDefault).name
    return name === 'autoincrement' || name === 'cuid' || name === 'uuid' || name === 'now' || name === 'auto'
  }
  return false
}

/**
 * Renders the TypeScript interface and CRUD input/where types for a single model.
 *
 * Emits four declarations:
 *  - `${name}` — flat interface of all scalar/enum fields
 *  - `${name}CreateInput` — required fields minus auto-generated ones
 *  - `${name}UpdateInput` — all non-id, non-auto fields as optional
 *  - `${name}WhereUniqueInput` — union of `@id` and `@unique` field selectors
 */
export function renderModelInterface(model: DMMF.Model): string {
  const dataFields = model.fields.filter(isDataField)
  const lines: string[] = []

  // Interface
  lines.push(`export interface ${model.name} {`)
  for (const f of dataFields) {
    lines.push(`  ${f.name}: ${fieldTsType(f)}`)
  }
  lines.push('}')
  lines.push('')

  // CreateInput — omit auto-generated ids and @updatedAt fields
  lines.push(`export type ${model.name}CreateInput = {`)
  for (const f of dataFields) {
    if (f.isId && isAutoGenerated(f)) continue
    if (f.isUpdatedAt) continue
    const optional = !f.isRequired || f.hasDefaultValue ? '?' : ''
    lines.push(`  ${f.name}${optional}: ${fieldTsType(f)}`)
  }
  lines.push('}')
  lines.push('')

