 *
 * The class extends the (unexported) `BaseRestClient` defined in the same
 * generated file and provides five CRUD methods that map to conventional REST
 * endpoints:
 *  - `findMany`   → GET  /{plural}?...
 *  - `findUnique` → GET  /{plural}/{id}  (falls back to filtered findMany for non-id unique fields)
 *  - `create`     → POST /{plural}
 *  - `update`     → PATCH /{plural}/{id}
 *  - `delete`     → DELETE /{plural}/{id}
 */
export function renderModelClient(model: DMMF.Model, pluralName: string): string {
  const id = idField(model)
  const idTsType = id ? (id.kind === 'enum' ? id.type : scalarToTs(id.type)) : 'string'
  const resourcePath = `/${pluralName}`
  const N = model.name

  // String concatenation instead of template literals keeps the generated
  // source free of backtick characters, avoiding escaping in the renderer.
  const lines: string[] = []

  lines.push(`export class ${N}Client extends BaseRestClient {`)

  // findMany
  lines.push(
    `  async findMany(params?: FindManyParams<${N}>): Promise<${N}[]> {`,
    `    const qs = params ? '?' + new URLSearchParams(encodeParams(params as Record<string, unknown>)).toString() : ''`,
    `    return this.request<${N}[]>('GET', '${resourcePath}' + qs)`,
    `  }`,
    '',
  )

  // findUnique — uses the @id path segment when available, falls back to a
  // filtered GET otherwise (non-id unique fields have no conventional URL form).
  lines.push(`  async findUnique(where: ${N}WhereUniqueInput): Promise<${N} | null> {`)
  if (id) {
    lines.push(
      `    if ('${id.name}' in where) {`,
      `      return this.request<${N} | null>('GET', '${resourcePath}/' + (where as { ${id.name}: ${idTsType} }).${id.name})`,
      `    }`,
      `    const results = await this.findMany({ where: where as Partial<${N}>, take: 1 })`,
      `    return results[0] ?? null`,
    )
  } else {
    lines.push(
      `    const results = await this.findMany({ where: where as Partial<${N}>, take: 1 })`,
      `    return results[0] ?? null`,
    )
  }
  lines.push(`  }`, '')

  // create
  lines.push(
    `  async create(data: ${N}CreateInput): Promise<${N}> {`,
    `    return this.request<${N}>('POST', '${resourcePath}', data)`,
    `  }`,
    '',
  )

  // update
  lines.push(`  async update(where: ${N}WhereUniqueInput, data: ${N}UpdateInput): Promise<${N}> {`)
  if (id) {
    lines.push(
      `    if ('${id.name}' in where) {`,
      `      return this.request<${N}>('PATCH', '${resourcePath}/' + (where as { ${id.name}: ${idTsType} }).${id.name}, data)`,
      `    }`,
      `    throw new Error('update via non-id unique fields is not supported for REST operations')`,
    )
  } else {
    lines.push(`    throw new Error('update requires an @id field on the model')`)
  }
  lines.push(`  }`, '')

  // delete
  lines.push(`  async delete(where: ${N}WhereUniqueInput): Promise<${N}> {`)
  if (id) {
    lines.push(
      `    if ('${id.name}' in where) {`,
      `      return this.request<${N}>('DELETE', '${resourcePath}/' + (where as { ${id.name}: ${idTsType} }).${id.name})`,
