      `    throw new Error('delete via non-id unique fields is not supported for REST operations')`,
    )
  } else {
    lines.push(`    throw new Error('delete requires an @id field on the model')`)
  }
  lines.push(`  }`)

  lines.push('}', '')

  return lines.join('\n')
}

