import type * as DMMF from '@prisma/dmmf'

/** Lowercases the first character of a string. */
function lowerFirst(s: string): string {
  return s.charAt(0).toLowerCase() + s.slice(1)
}

/**
 * Renders the root `PrismaRestClient` class that aggregates one typed
 * per-model client per property, mirroring the PrismaClient API surface.
 *
 * Usage example in the generated file:
 * ```ts
 * export const client = new PrismaRestClient('https://api.example.com')
 * const users = await client.user.findMany()
 * ```
 */
export function renderRootClient(models: readonly DMMF.Model[]): string {
  const lines: string[] = ['// ----- Root client -----', '']

  lines.push('export class PrismaRestClient {')

  for (const m of models) {
    lines.push(`  readonly ${lowerFirst(m.name)}: ${m.name}Client`)
  }

  lines.push(
    '',
    '  constructor(',
    '    baseUrl: string,',
    '    fetchFn: (input: string, init?: RequestInit) => Promise<Response> = fetch,',
    '  ) {',
  )

  for (const m of models) {
    lines.push(`    this.${lowerFirst(m.name)} = new ${m.name}Client(baseUrl, fetchFn)`)
  }

  lines.push('  }', '}', '')

  return lines.join('\n')
}

