import fs from 'node:fs/promises'
import path from 'node:path'
import type * as DMMF from '@prisma/dmmf'
import { renderBaseInfra } from './render-base-infra'
import { renderEnums } from './render-enums'
import { renderModelClient } from './render-model-client'
import { renderModelInterface } from './render-model-interface'
import { renderRootClient } from './render-root-client'

export interface GenerateRestClientOptions {
  dmmf: DMMF.Document
  outputDir: string
}

/**
 * Generates a single `index.ts` file inside `outputDir` containing:
 *  1. Enum union types
 *  2. Model interfaces and CRUD input/where types
 *  3. Shared infrastructure (FindManyParams, BaseRestClient)
 *  4. Per-model HTTP client classes
 *  5. Root `PrismaRestClient` aggregator class
 *
 * Sections are ordered so every identifier is declared before first use,
 * meaning the generated file compiles without forward references.
 */
export async function generateRestClient({ dmmf, outputDir }: GenerateRestClientOptions): Promise<void> {
  const { datamodel, mappings } = dmmf

  // DMMF already provides the conventional plural form for each model
  const pluralByModel = new Map<string, string>()
  for (const mapping of mappings.modelOperations) {
    pluralByModel.set(mapping.model, mapping.plural)
  }

  const sections: string[] = [
    '// Generated by @prisma/client-generator-rest-api',
    '// Do not edit this file manually.',
    '',
  ]

  const enumSection = renderEnums(datamodel.enums)
  if (enumSection) sections.push(enumSection)

  sections.push('// ----- Model interfaces and input types -----', '')
  for (const model of datamodel.models) {
    sections.push(renderModelInterface(model))
  }

  sections.push(renderBaseInfra())

  sections.push('// ----- Per-model clients -----', '')
  for (const model of datamodel.models) {
    const plural = pluralByModel.get(model.name) ?? model.name.toLowerCase() + 's'
    sections.push(renderModelClient(model, plural))
  }

  sections.push(renderRootClient(datamodel.models))

  await fs.mkdir(outputDir, { recursive: true })
  await fs.writeFile(path.join(outputDir, 'index.ts'), sections.join('\n'), 'utf-8')
}

