import type * as DMMF from '@prisma/dmmf'
import { renderEnums } from '../render-enums'

describe('renderEnums', () => {
  it('returns an empty string when there are no enums', () => {
    expect(renderEnums([])).toBe('')
  })

  it('renders a single enum as a TypeScript string union type', () => {
    const enums: DMMF.DatamodelEnum[] = [
      {
        name: 'Role',
        values: [
          { name: 'USER', dbName: null },
          { name: 'ADMIN', dbName: null },
        ],
      },
    ] as unknown as DMMF.DatamodelEnum[]

    const result = renderEnums(enums)
    expect(result).toContain("export type Role = 'USER' | 'ADMIN'")
  })

  it('renders multiple enums separated by blank lines', () => {
    const enums: DMMF.DatamodelEnum[] = [
      { name: 'Color', values: [{ name: 'RED', dbName: null }, { name: 'BLUE', dbName: null }] },
      { name: 'Size', values: [{ name: 'S', dbName: null }, { name: 'M', dbName: null }, { name: 'L', dbName: null }] },
    ] as unknown as DMMF.DatamodelEnum[]

    const result = renderEnums(enums)
    expect(result).toContain("export type Color = 'RED' | 'BLUE'")
    expect(result).toContain("export type Size = 'S' | 'M' | 'L'")
  })
})

