describe('renderModelInterface — User model', () => {
  const output = renderModelInterface(userModel)

  it('emits the model interface with scalar and enum fields', () => {
    expect(output).toContain('export interface User {')
    expect(output).toContain('id: number')
    expect(output).toContain('email: string')
    expect(output).toContain('name: string | null')
    expect(output).toContain('role: Role')
    expect(output).toContain('createdAt: string')
  })

  it('does not include relation fields in the interface', () => {
    // The `posts` field is a relation (kind: 'object') and must be excluded
